const body = $input.first().json.body || $input.first().json;

let telefon = '';
let tipRaspuns = 'neclar';
let dataNou = '';
let oraNou = '';
let tipApel = 'outbound';

// Detecteaza directia apelului (inbound vs outbound)
const callDirection = body.data?.metadata?.phone_call?.direction || '';
const dynVars = body.data?.metadata?.dynamic_variables || body.data?.conversation_initiation_client_data?.dynamic_variables || {};
if (callDirection === 'inbound' || dynVars.tip_apel === 'inbound') {
  tipApel = 'inbound';
}

// Extrage telefonul
const callerIdRaw = body.data?.metadata?.phone_call?.external_number || '';
telefon = callerIdRaw.replace(/^\+40/, '0').replace(/\D/g, '');
telefon = telefon.toString().replace(/\D/g, '');
if (telefon.startsWith('40') && telefon.length === 11) telefon = '0' + telefon.slice(2);
else if (telefon.startsWith('+40')) telefon = '0' + telefon.slice(3);
else if (!telefon.startsWith('0') && telefon.length === 9) telefon = '0' + telefon;

// Daca apelul a esuat (fara transcript) sau este inbound, OPRESTE fluxul
if (!body.data || !body.data.transcript || body.data.transcript.length === 0) {
  return [];
}

// Daca este apel inbound, nu procesa ca confirmare outbound - OPRESTE fluxul
if (tipApel === 'inbound') {
  return [];
}

const transcript = body.data.transcript || [];
const userMessages = transcript
  .filter(msg => msg.role === 'user')
  .map(msg => msg.message)
  .join(' ').toLowerCase();

if (userMessages.trim().length < 3) {
  tipRaspuns = 'neclar';
} else {
  const esteReprogramare = userMessages.includes('reprogramez') ||
                            userMessages.includes('alta zi') ||
                            userMessages.includes('mut');

  const esteAnulare = userMessages.includes('anulez') ||
                      userMessages.includes('nu pot') ||
                      userMessages.includes('nu mai vin') ||
                      userMessages.includes('nu mai vreau');

  const esteConfirmare = userMessages.includes('da') ||
                         userMessages.includes('confirm') ||
                         userMessages.includes('vin') ||
                         userMessages.includes('ok') ||
                         userMessages.includes('bine');

  if (esteReprogramare) tipRaspuns = 'reprogramare';
  else if (esteAnulare) tipRaspuns = 'anulare';
  else if (esteConfirmare) tipRaspuns = 'confirmare';
  else tipRaspuns = 'neclar';
}

const vars = body.data?.collected_data || {};
dataNou = vars.data_noua || '';
oraNou = vars.ora_noua || '';

return {
  json: { tipRaspuns, telefon, dataNou, oraNou, tipApel }
};

const item = $input.first().json;

const mesaj = `Buna ziua, ${item.NUME}, aveti programare maine ${item['DATA PROGRAMARII']} la ora ${item.ORA}.\nConfirmati prezenta aici: https://andreidamian.app.n8n.cloud/webhook/confirmare?tel=${item.TELEFON}`;

// Populeaza cache la trimiterea SMS-ului (nu doar la apel outbound)
const staticData = $getWorkflowStaticData('global');
staticData.clientCache = staticData.clientCache || {};
const cheieCache = item.TELEFON.toString().replace(/\D/g, '');
staticData.clientCache[cheieCache] = {
  nume: item.NUME,
  ora: item.ORA,
  data: item['DATA PROGRAMARII'],
  smsTrimis: 'TRIMIS',
  apelTrimis: item.APEL_TRIMIS || '',
  status: item.STATUS || ''
};

return [{
  json: {
    ...item,
    mesaj_sms: mesaj
  }
}];

const item = $input.first().json;

const acum = $now;
const dataAzi = acum.toFormat('dd.MM.yyyy');

if (item.DATA !== dataAzi) return [];

const status = (item.STATUS || '').trim();
if (status !== '') return [];

const [h, m] = item.ORA.split(':').map(Number);
const oraApel = acum.startOf('day').plus({ hours: h, minutes: m + 10 });

const start = acum.minus({ minutes: 30 });
const end = acum;

if (oraApel < start || oraApel > end) return [];

let telefon = item.TELEFON.toString().replace(/\D/g, '');
if (telefon.startsWith('0')) {
  telefon = '+4' + telefon;
} else if (!telefon.startsWith('+')) {
  telefon = '+40' + telefon;
}

return {
  json: {
    ...item,
    telefon_formatat: telefon,
    nume: item.NUME,
    data_programarii: item.DATA,
    ora_programarii: item.ORA,
    serviciu: item.SERVICIU || ''
  }
};

const body = $input.first().json.body || $input.first().json;

let telefon = '';
let tipRaspuns = 'invalid';
let dataNou = '';
let oraNou = '';

if (body.data && body.data.transcript) {
  const transcript = body.data.transcript || [];
  const userMessages = transcript
    .filter(msg => msg.role === 'user')
    .map(msg => msg.message)
    .join(' ').toLowerCase();

  const vreaReprogramare = userMessages.includes('da') ||
                           userMessages.includes('reprogramez') ||
                           userMessages.includes('alta zi') ||
                           userMessages.includes('vreau');

  const refuzaReprogramare = userMessages.includes('nu') ||
                              userMessages.includes('nu mai vreau') ||
                              userMessages.includes('renunt');

  if (vreaReprogramare && !refuzaReprogramare) tipRaspuns = 'reprogramare';
  else tipRaspuns = 'invalid';

  const vars = body.data?.collected_data || {};
  dataNou = vars.data_noua || '';
  oraNou = vars.ora_noua || '';

  const callerIdRaw = body.data?.metadata?.phone_call?.external_number || '';
  telefon = callerIdRaw.replace(/^\+40/, '0').replace(/\D/g, '');
}

telefon = telefon.toString().replace(/\D/g, '');
if (telefon.startsWith('40') && telefon.length === 11) telefon = '0' + telefon.slice(2);
else if (telefon.startsWith('+40')) telefon = '0' + telefon.slice(3);
else if (!telefon.startsWith('0') && telefon.length === 9) telefon = '0' + telefon;

return {
  json: { tipRaspuns, telefon, dataNou, oraNou }
};

const body = $input.first().json.body || $input.first().json;

const data = body.data || '';
const ora = body.ora || '';

const [zi, luna, an] = data.split('.');
const [h, m] = ora.split(':');

const start = new Date(parseInt(an), parseInt(luna)-1, parseInt(zi), parseInt(h), parseInt(m));
const end = new Date(start.getTime() + 60 * 60 * 1000);

const oraStart = parseInt(h);
if (oraStart < 9 || oraStart >= 18) {
  return { json: { disponibil: false, motiv: 'In afara programului. Programul este intre 09:00 si 18:00.' } };
}

return {
  json: {
    disponibil: null,
    start_iso: start.toISOString(),
    end_iso: end.toISOString(),
    data,
    ora
  }
};

const events = $input.all();
const startIso = $('Code - Verifica Interval Program').first().json.start_iso;
const endIso = $('Code - Verifica Interval Program').first().json.end_iso;

const areEvents = events.some(e => e.json && e.json.id);

return {
  json: {
    disponibil: !areEvents,
    motiv: areEvents ? 'Ora selectata este deja ocupata. Va rugam alegeti alta ora.' : 'Ora este disponibila.',
    start_iso: startIso,
    end_iso: endIso
  }
};

const body = $input.first().json.body || $input.first().json;

const telefon = body.telefon || '';
const dataNoua = body.data_noua || '';
const oraNoua = body.ora_noua || '';

const [zi, luna, an] = dataNoua.split('.');
const [h, m] = oraNoua.split(':');

const start = new Date(parseInt(an), parseInt(luna)-1, parseInt(zi), parseInt(h), parseInt(m));
const end = new Date(start.getTime() + 60 * 60 * 1000);

let telefonCurat = telefon.toString().replace(/\D/g, '');
if (telefonCurat.startsWith('40')) telefonCurat = '0' + telefonCurat.slice(2);
else if (telefonCurat.startsWith('+40')) telefonCurat = '0' + telefonCurat.slice(3);

return {
  json: {
    telefon: telefonCurat,
    data_noua: dataNoua,
    ora_noua: oraNoua,
    start_iso: start.toISOString(),
    end_iso: end.toISOString()
  }
};

const client = $input.first().json;
const reprog = $('Code - Pregateste Reprogramare').first().json;

const titlu = `${client.NUME} - Programare`;

return {
  json: {
    ...reprog,
    nume: client.NUME,
    titlu_calendar: titlu,
    data_veche: client['DATA PROGRAMARII'],
    ora_veche: client.ORA
  }
};

const body = $input.first().json.body || $input.first().json;

let telefon = body.telefon || '';
telefon = telefon.toString().replace(/\D/g, '');
if (telefon.startsWith('40') && telefon.length === 11) telefon = '0' + telefon.slice(2);
else if (telefon.startsWith('+40')) telefon = '0' + telefon.slice(3);
else if (!telefon.startsWith('0') && telefon.length === 9) telefon = '0' + telefon;

return { json: { telefon } };

return $input.all().map(item => {
  const raw = item.json;

  let telefon = String(raw.TELEFON || '').replace(/\D/g, '');
  if (telefon.startsWith('40')) telefon = '0' + telefon.slice(2);
  if (!telefon.startsWith('0')) telefon = '0' + telefon;

  return {
    json: {
      NUME:               raw.NUME                || '',
      TELEFON:            telefon,
      SERVICIU:           raw.SERVICIU            || '',
      'DATA PROGRAMARII': raw['DATA PROGRAMARII'] || '',
      ORA:                raw.ORA                 || ''
    }
  };
});

const preparat = $('Code - Pregateste Date NO SHOW').all();

return preparat.map(item => ({
  json: {
    NUME:               item.json.NUME               || '',
    TELEFON:            item.json.TELEFON             || '',
    SERVICIU:           item.json.SERVICIU            || '',
    'DATA PROGRAMARII': item.json['DATA PROGRAMARII'] || '',
    ORA:                item.json.ORA                 || ''
  }
}));

const body = $input.first().json.body || $input.first().json;

const nume = body.nume || '';
const telefon = body.telefon || '';
const dataRaw = body.data || '';
const oraRaw = body.ora || '12:00';

// === PARSARE DATA ROBUSTA ===
function parseData(dataStr) {
  const lower = dataStr.toLowerCase().trim();

  // Text natural - verificam INTAI textul, inainte de formate cu puncte/liniute
  const now = new Date();
  // Folosim ora Romaniei (UTC+2 / UTC+3)
  const nowRO = new Date(now.toLocaleString('en-US', { timeZone: 'Europe/Bucharest' }));

  if (lower === 'maine' || lower === 'mâine') {
    const d = new Date(nowRO);
    d.setDate(d.getDate() + 1);
    return d;
  }

  if (lower === 'azi' || lower === 'astazi' || lower === 'astăzi') {
    return nowRO;
  }

  // Zile saptamana viitoare (ex: "joi viitoare") - verificam INTAI
  const zileSaptViitoare = {
    'luni viitoare': 1,
    'marti viitoare': 2, 'marți viitoare': 2,
    'miercuri viitoare': 3,
    'joi viitoare': 4,
    'vineri viitoare': 5,
    'sambata viitoare': 6, 'sâmbătă viitoare': 6, 'sâmbăta viitoare': 6
  };

  if (zileSaptViitoare[lower] !== undefined) {
    const target = zileSaptViitoare[lower];
    const d = new Date(nowRO);
    const ziAzi = d.getDay() === 0 ? 7 : d.getDay(); // 1=luni...7=duminica
    let diff = target - ziAzi;
    if (diff <= 0) diff += 7; // urmatoarea saptamana curenta
    diff += 7;                 // + inca o saptamana = saptamana viitoare
    d.setDate(d.getDate() + diff);
    return d;
  }

  // Zile saptamana curenta/urmatoare (ex: "joi", "luni")
  const zile = {
    'luni': 1,
    'marti': 2, 'marți': 2,
    'miercuri': 3,
    'joi': 4,
    'vineri': 5,
    'sambata': 6, 'sâmbătă': 6, 'sâmbăta': 6
  };

  if (zile[lower] !== undefined) {
    const target = zile[lower];
    const d = new Date(nowRO);
    // Convertim getDay() (0=dum, 1=lun...) la (1=lun...7=dum)
    const ziAzi = d.getDay() === 0 ? 7 : d.getDay();
    let diff = target - ziAzi;
    if (diff <= 0) diff += 7; // daca ziua a trecut sau e azi, mergi la saptamana viitoare
    d.setDate(d.getDate() + diff);
    return d;
  }

  // Format dd.MM.yyyy
  if (dataStr.includes('.')) {
    const parts = dataStr.split('.');
    if (parts.length === 3) {
      const z = parseInt(parts[0]), l = parseInt(parts[1]), a = parseInt(parts[2]);
      if (!isNaN(z) && !isNaN(l) && !isNaN(a) && a > 100) {
        return new Date(a, l - 1, z);
      }
    }
  }

  // Format yyyy-MM-dd
  if (dataStr.includes('-') && dataStr.length >= 10) {
    const parts = dataStr.split('-');
    if (parts.length === 3) {
      const a = parseInt(parts[0]), l = parseInt(parts[1]), z = parseInt(parts[2]);
      if (!isNaN(z) && !isNaN(l) && !isNaN(a) && a > 100) {
        return new Date(a, l - 1, z);
      }
    }
  }

  return null;
}

const dataParsed = parseData(dataRaw);

if (!dataParsed || isNaN(dataParsed.getTime())) {
  return { json: { error: true, mesaj: 'Nu am putut intelege data: ' + dataRaw + '. Va rog specificati din nou (ex: joi, 2 aprilie, sau 02.04.2026).' } };
}

// Formateaza data ca dd.MM.yyyy pentru Sheet
const zi = String(dataParsed.getDate()).padStart(2, '0');
const luna = String(dataParsed.getMonth() + 1).padStart(2, '0');
const an = dataParsed.getFullYear();
const dataFormatata = `${zi}.${luna}.${an}`;

// Parseaza ora
const [h, m] = oraRaw.split(':').map(Number);
const oraH = isNaN(h) ? 12 : h;
const oraM = isNaN(m) ? 0 : m;

const start = new Date(an, dataParsed.getMonth(), dataParsed.getDate(), oraH, oraM);
const end = new Date(start.getTime() + 60 * 60 * 1000);

// Normalizeaza telefon
let telefonCurat = telefon.toString().replace(/\D/g, '');
if (telefonCurat.startsWith('0')) telefonCurat = '+4' + telefonCurat;
else if (!telefonCurat.startsWith('+')) telefonCurat = '+40' + telefonCurat;

return {
  json: {
    nume,
    telefon,
    telefon_curat: telefonCurat,
    serviciu: 'consult',
    data: dataFormatata,
    ora: oraRaw,
    start_iso: start.toISOString(),
    end_iso: end.toISOString(),
    titlu_calendar: `${nume} - Programare`,
    // debug - poti sterge dupa ce verifici ca merge
    debug_dataRaw: dataRaw,
    debug_dataCalculata: dataFormatata
  }
};

const item = $input.first().json;

let telefon = item.TELEFON.toString().replace(/\D/g, '');
if (telefon.startsWith('0')) {
  telefon = '+4' + telefon;
} else if (!telefon.startsWith('+')) {
  telefon = '+40' + telefon;
}

// Salveaza date client in cache pentru apeluri inbound
const staticData = $getWorkflowStaticData('global');
staticData.clientCache = staticData.clientCache || {};
const cheieCache = item.TELEFON.toString().replace(/\D/g, '');
staticData.clientCache[cheieCache] = {
  nume: item.NUME,
  ora: item.ORA,
  data: item['DATA PROGRAMARII'],
  smsTrimis: item.SMS_TRIMIS || '',
  apelTrimis: item.APEL_TRIMIS || '',
  status: item.STATUS || ''
};

return {
  json: {
    ...item,
    telefon_formatat: telefon,
    nume: item.NUME,
    data_programarii: item['DATA PROGRAMARII'],
    ora_programarii: item.ORA,
    serviciu: item.SERVICIU
  }
};

const body = $input.first().json.body || $input.first().json;

// ElevenLabs trimite caller_id
let telefon = body.caller_id || body.telefon || body.phone_number || '';

telefon = telefon.toString().replace(/\D/g, '');

if (telefon.startsWith('40') && telefon.length === 11) {
  telefon = '0' + telefon.slice(2);
} else if (telefon.startsWith('4') && telefon.length === 10) {
  telefon = '0' + telefon.slice(1);
} else if (!telefon.startsWith('0') && telefon.length === 9) {
  telefon = '0' + telefon;
}

// Citeste date client din cache (salvat la outbound) - instant, fara Sheets
const staticData = $getWorkflowStaticData('global');
const cache = staticData.clientCache || {};
const clientData = cache[telefon] || {};

return {
  json: {
    telefon,
    nume: clientData.nume || '',
    ora: clientData.ora || '',
    data: clientData.data || '',
    smsTrimis: clientData.smsTrimis || '',
    apelTrimis: clientData.apelTrimis || '',
    status: clientData.status || ''
  }
};

const client = $input.first().json;

// Suporta atat date din cache (lowercase) cat si din Sheets (uppercase)
const telefon = (client.telefon || client.TELEFON || '').toString().trim();
const nume = (client.nume || client.NUME || '').trim();
const data = (client.data || client['DATA PROGRAMARII'] || '').trim();
const ora = (client.ora || client.ORA || '').trim();
const status = (client.status || client.STATUS || '').trim();
const smsTrimis = (client.smsTrimis || client.SMS_TRIMIS || '').trim();
const apelTrimis = (client.apelTrimis || client.APEL_TRIMIS || '').trim();

let tipContext = '';
let firstMessage = '';

// PRIORITATE 1: SMS sau APEL trimis si inca neconfirmat = REAMINTIRE
if ((smsTrimis === 'TRIMIS' || apelTrimis === 'TRIMIS') && status !== 'VALID' && status !== 'INVALID') {
  tipContext = 'confirmare';
  firstMessage = 'Buna ziua, ' + nume + '! Vă sunăm de la clinica noastră. Vreau să vă reamitesc că mâine la ora ' + ora + ' aveți programare la noi. Rămâne că veniți?';

// PRIORITATE 2: Deja confirmat
} else if (status === 'VALID') {
  tipContext = 'confirmat';
  firstMessage = 'Buna ziua, ' + nume + '! Programarea dumneavoastra de maine la ora ' + ora + ' este deja confirmata. Cu ce va mai putem ajuta?';

// PRIORITATE 3: Nu are programare
} else {
  tipContext = 'fara_programare';
  firstMessage = 'Buna ziua! Clinica X, cu ce va putem ajuta?';
}

return {
  json: {
    tipContext,
    firstMessage,
    nume,
    telefon,
    data,
    ora,
    status,
    smsTrimis,
    apelTrimis
  }
};

const item = $input.first().json;

const raspuns = {
  type: 'conversation_initiation_client_data',
  dynamic_variables: {
    tipContext: item.tipContext,
    nume: item.nume,
    name: item.nume,
    ora: item.ora,
    data: item.data,
    serviciu: 'consult',
    tip_apel: 'inbound'
  }
};

return { json: raspuns };
